/**
 * Seed Analyses Script — Adds full timeline event analyses for all 71 policies.
 *
 * Run: node src/seed-analyses.js
 *
 * This script reads the 4 analysis files generated by research agents and
 * upserts them as timeline_events in Supabase, linked to existing policies.
 * Safe to run multiple times (skips existing events).
 */

import 'dotenv/config'
import { validateEnv } from './lib/env.js'
import supabase from './db/client.js'
import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))

validateEnv(['SUPABASE_URL', 'SUPABASE_SERVICE_KEY'])

// ============================
// Load analysis files
// ============================
function loadAnalysisFile(filePath) {
  const content = fs.readFileSync(filePath, 'utf8')
  const start = content.indexOf('[')
  const end = content.lastIndexOf(']') + 1
  const arrayStr = content.substring(start, end)
  const fn = new Function('return ' + arrayStr)
  return fn()
}

async function seedAnalyses() {
  console.log('📊 Seeding timeline event analyses for all policies\n')

  // Load all analysis files
  const analysisDir = path.join(__dirname, '..', 'analyses')
  const files = [
    'mining-energy.js',
    'tax-property.js',
    'health-super-defence.js',
    'remaining.js',
  ]

  let allAnalyses = []
  for (const f of files) {
    const filePath = path.join(analysisDir, f)
    if (!fs.existsSync(filePath)) {
      console.log(`⚠ File not found: ${f}`)
      continue
    }
    const entries = loadAnalysisFile(filePath)
    console.log(`  Loaded ${entries.length} analyses from ${f}`)
    allAnalyses.push(...entries)
  }
  console.log(`\n  Total new analyses: ${allAnalyses.length}\n`)

  // Get all policy IDs from Supabase
  const { data: allPolicies, error: pErr } = await supabase
    .from('policies')
    .select('id, external_id')
    .like('external_id', 'au-pol-%')

  if (pErr) {
    console.error('Failed to fetch policies:', pErr.message)
    process.exit(1)
  }

  const policyMap = {}
  for (const p of (allPolicies || [])) {
    policyMap[p.external_id] = p.id
  }
  console.log(`  Found ${Object.keys(policyMap).length} policies in database\n`)

  // Insert timeline events
  let inserted = 0
  let skipped = 0
  let errors = 0

  for (const te of allAnalyses) {
    const policyId = policyMap[te.ext]
    if (!policyId) {
      console.log(`  ⚠ Policy not found: ${te.ext} — skipping`)
      skipped++
      continue
    }

    // Check if timeline event already exists for this policy
    const { data: existing } = await supabase
      .from('timeline_events')
      .select('id')
      .eq('policy_id', policyId)
      .limit(1)

    if (existing?.length) {
      skipped++
      continue
    }

    // Build the event object (strip 'ext' field, add policy_id)
    const { ext, ...eventData } = te
    const { error } = await supabase
      .from('timeline_events')
      .insert({ ...eventData, policy_id: policyId })

    if (error) {
      console.log(`  ✗ Error (${te.ext}): ${error.message}`)
      errors++
    } else {
      inserted++
    }
  }

  console.log(`\n✅ Analysis seed complete!`)
  console.log(`   ${inserted} new timeline events inserted`)
  console.log(`   ${skipped} skipped (already exist or policy not found)`)
  if (errors) console.log(`   ${errors} errors`)

  // Verify total
  const { count } = await supabase
    .from('timeline_events')
    .select('*', { count: 'exact', head: true })

  console.log(`\n   Total timeline events in database: ${count}`)
}

seedAnalyses().catch(err => {
  console.error('Seed failed:', err.message)
  process.exit(1)
})
